public interface IShapeVisitor {
  void VisitCircle(Circle circle);
  void VisitRectangle(Rectangle rectangle);
}

public interface IShape {
  void Accept(IShapeVisitor visitor);
}

public class Circle : IShape {
  public double Radius { get; }
  public Circle(double radius) { Radius = radius; }
  public void Accept(IShapeVisitor visitor) => visitor.VisitCircle(this);
}

public class Rectangle : IShape {
  public double Width { get; }
  public double Height { get; }
  public Rectangle(double w, double h) { Width = w; Height = h; }
  public void Accept(IShapeVisitor visitor) => visitor.VisitRectangle(this);
}

public class AreaVisitor : IShapeVisitor {
  public double Area { get; private set; }
  public void VisitCircle(Circle c) => Area += Math.PI * c.Radius * c.Radius;
  public void VisitRectangle(Rectangle r) => Area += r.Width * r.Height;
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Visitor_ComputesAreaAcrossDifferentElements() {
  IShape[] shapes = { new Circle(1), new Rectangle(2, 3) };
  var visitor = new AreaVisitor();
  foreach (var shape in shapes) shape.Accept(visitor);
  Assert.IsTrue(visitor.Area > 0);
}

[TestMethod]
public void Elements_AcceptVisitorWithoutChangingElementClasses() {
  var circle = new Circle(2);
  var visitor = new AreaVisitor();
  circle.Accept(visitor);
  Assert.IsTrue(visitor.Area > 0);
}
